 11→export function createDeterministicIdGenerator(seed: string): () => string {
 12→  let counter = 0;
 13→  return () => {
 14→    const hash = createHash("sha256").update(`${seed}:${counter++}`).digest("hex");
 15→    return `${hash.slice(0, 8)}-${hash.slice(8, 12)}-${hash.slice(12, 16)}-${hash.slice(16, 20)}-${hash.slice(20, 32)}`;
 16→  };
 17→}
 18→
 19→export type EvalRuntime = {
 20→  surreal: Surreal;
 21→  extractionModel: any;
 22→  embeddingModel: any;
 23→  chatAgentModel: any;
 24→  config: ServerConfig;
 25→  namespace: string;
 26→  database: string;
 27→};
 28→
 29→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 30→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 31→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 32→const schemaPath = join(process.cwd(), "schema", "surreal-schema.surql");
 33→
 34→export async function setupEvalRuntime(suiteName: string): Promise<EvalRuntime> {
 35→  const namespace = `eval_${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 36→  const database = `${suiteName}_${Math.floor(Math.random() * 100000)}`;
 37→
 38→  const surreal = new Surreal();
 39→  await surreal.connect(surrealUrl);
 40→  await surreal.signin({ username: surrealUsername, password: surrealPassword });
 41→
 42→  // SurrealDB can throw "Cannot perform subtraction with 'NONE'" during
 43→  // namespace/database operations when leftover computed fields exist.
 44→  // Swallow these benign errors during setup.
 45→  const setupQuery = async (sql: string) => {
 46→    await surreal.query(sql).catch((error) => {
 47→      if (!isAlreadyExistsError(error) && !isNoneSubtractionError(error)) throw error;
 48→    });
 49→  };
 50→  await setupQuery(`DEFINE NAMESPACE IF NOT EXISTS ${namespace};`);
 51→  await surreal.use({ namespace, database: undefined as any });
 52→  await setupQuery(`REMOVE DATABASE IF EXISTS ${database};`);
 53→  await setupQuery(`DEFINE DATABASE IF NOT EXISTS ${database};`);
 54→  await surreal.use({ namespace, database });
 55→
 56→  const schemaSql = readFileSync(schemaPath, "utf8");
 57→  // Split schema into individual statements to isolate errors.
 58→  // SurrealDB multi-statement queries can fail mid-batch; splitting lets us
 59→  // skip benign runtime errors (like subtraction on NONE in DEFINE FUNCTION
 60→  // validation) while still applying all schema definitions.
 61→  const schemaStatements = splitSurqlStatements(schemaSql);
 62→  for (const stmt of schemaStatements) {
 63→    await surreal.query(stmt).catch((error) => {
 64→      if (!isAlreadyExistsError(error) && !isNoneSubtractionError(error)) throw error;
 65→    });
 66→  }
 67→
 68→  // Apply migrations for production parity
 69→  const migrationsDir = join(process.cwd(), "schema", "migrations");
 70→  const migrationFiles = readdirSync(migrationsDir)
 71→    .filter((f) => f.endsWith(".surql"))
 72→    .sort();
 73→  for (const file of migrationFiles) {
 74→    const migrationSql = readFileSync(join(migrationsDir, file), "utf8");
 75→    await surreal.query(migrationSql).catch((error) => {
 76→      if (!isAlreadyExistsError(error) && !isNoneSubtractionError(error)) {
 77→        console.error(`✗ Failed: ${file}`, error);
 78→        throw error;
 79→      }
 80→    });
 81→  }
 82→
 83→  const openRouterApiKey = requireEnv("OPENROUTER_API_KEY");
 84→  const extractionModelId = requireEnv("EXTRACTION_MODEL");
 85→  const chatAgentModelId = requireEnv("CHAT_AGENT_MODEL");
 86→  const embeddingModelId = requireEnv("OPENROUTER_EMBEDDING_MODEL");
 87→  const embeddingDimension = Number(requireEnv("EMBEDDING_DIMENSION"));
 88→  const extractionStoreThreshold = Number(process.env.EXTRACTION_STORE_THRESHOLD ?? "0.3");
 89→  const extractionDisplayThreshold = Number(process.env.EXTRACTION_DISPLAY_THRESHOLD ?? "0.5");
 90→
 91→  const openrouter = createOpenRouter({ apiKey: openRouterApiKey });
 92→  const extractionModel = openrouter(extractionModelId, { plugins: [{ id: "response-healing" }] });
 93→  const chatAgentModel = openrouter(chatAgentModelId, { plugins: [{ id: "response-healing" }] });
 94→  const embeddingModel = openrouter.textEmbeddingModel(embeddingModelId);
 95→
 96→  const pmAgentModelId = process.env.PM_AGENT_MODEL?.trim() || extractionModelId;
 97→  const analyticsAgentModelId = process.env.ANALYTICS_MODEL?.trim() || "unknown";
 98→
 99→  const config: ServerConfig = {
100→    openRouterApiKey,
101→    chatAgentModelId,
102→    extractionModelId,
103→    pmAgentModelId,
104→    analyticsAgentModelId,
105→    embeddingModelId,
106→    embeddingDimension,
107→    extractionStoreThreshold,
108→    extractionDisplayThreshold,
109→    surrealUrl,
110→    surrealUsername,
111→    surrealPassword,
112→    surrealNamespace: namespace,
113→    surrealDatabase: database,
114→    port: 0,
115→  };
116→
117→  return {
118→    surreal,
119→    extractionModel,
120→    embeddingModel,
121→    chatAgentModel,
122→    config,
123→    namespace,
124→    database,
125→  };
126→}
