    await surreal.create(seededMessageRecord).content({
      conversation: conversationRecord,
      role: message.role,
      text: message.text,
      createdAt: new Date(now + index),
    });
    messageIds.push(seededMessageRecord.id as string);
  }
  return messageIds;
}

